"""Transform YAML file by converting all string values to uppercase."""

def parse_yaml_simple(content):
    """Simple YAML parser for basic structures."""
    import re

    lines = content.strip().split('\n')

    def parse_value(value):
        """Parse a YAML value."""
        value = value.strip()
        # Check if it's a number
        try:
            if '.' in value:
                return float(value)
            return int(value)
        except ValueError:
            # It's a string
            return value

    def parse_lines(lines, indent_level=0):
        """Recursively parse YAML lines."""
        result = {}
        i = 0
        current_key = None

        while i < len(lines):
            line = lines[i]

            # Skip empty lines
            if not line.strip():
                i += 1
                continue

            # Count indentation
            indent = len(line) - len(line.lstrip())

            # If indentation is less than expected, we've finished this level
            if indent < indent_level:
                break

            # If indentation is more than expected, skip (will be handled recursively)
            if indent > indent_level:
                i += 1
                continue

            # Parse the line
            line_content = line.strip()

            # Check if it's a list item
            if line_content.startswith('- '):
                # We're in a list
                list_items = []
                while i < len(lines):
                    line = lines[i]
                    indent = len(line) - len(line.lstrip())

                    if indent < indent_level:
                        break

                    if indent == indent_level and line.strip().startswith('- '):
                        item_value = line.strip()[2:].strip()
                        list_items.append(parse_value(item_value))
                        i += 1
                    else:
                        break

                return list_items

            # Check if it's a key-value pair
            if ': ' in line_content or line_content.endswith(':'):
                if line_content.endswith(':'):
                    key = line_content[:-1]
                    value = None
                else:
                    key, value = line_content.split(': ', 1)

                key = key.strip()

                # Look ahead to see if next line is indented (nested structure)
                if i + 1 < len(lines):
                    next_indent = len(lines[i + 1]) - len(lines[i + 1].lstrip())

                    if next_indent > indent_level:
                        # Nested structure
                        nested_lines = []
                        j = i + 1
                        while j < len(lines):
                            nested_indent = len(lines[j]) - len(lines[j].lstrip())
                            if nested_indent <= indent_level:
                                break
                            nested_lines.append(lines[j])
                            j += 1

                        result[key] = parse_lines(nested_lines, next_indent)
                        i = j
                        continue

                # Simple key-value pair
                if value is not None:
                    result[key] = parse_value(value)
                else:
                    result[key] = {}

            i += 1

        return result

    return parse_lines(lines, 0)


def transform_to_uppercase(data):
    """Recursively transform all string values to uppercase."""
    if isinstance(data, dict):
        return {key: transform_to_uppercase(value) for key, value in data.items()}
    elif isinstance(data, list):
        return [transform_to_uppercase(item) for item in data]
    elif isinstance(data, str):
        return data.upper()
    else:
        # Keep numeric and other types as-is
        return data


def dict_to_yaml(data, indent=0):
    """Convert dictionary to YAML format."""
    lines = []
    indent_str = '  ' * indent

    if isinstance(data, dict):
        for key, value in data.items():
            if isinstance(value, dict):
                lines.append(f"{indent_str}{key}:")
                lines.append(dict_to_yaml(value, indent + 1))
            elif isinstance(value, list):
                lines.append(f"{indent_str}{key}:")
                for item in value:
                    if isinstance(item, (dict, list)):
                        lines.append(dict_to_yaml(item, indent + 1))
                    else:
                        lines.append(f"{indent_str}  - {item}")
            else:
                lines.append(f"{indent_str}{key}: {value}")
    elif isinstance(data, list):
        for item in data:
            if isinstance(item, (dict, list)):
                lines.append(dict_to_yaml(item, indent))
            else:
                lines.append(f"{indent_str}- {item}")

    return '\n'.join(lines)


# Read the original YAML file
with open('/workspace/config.yaml', 'r') as f:
    content = f.read()

print("Original YAML content:")
print(content)
print()

# Parse the YAML
config = parse_yaml_simple(content)
print("Parsed config:")
print(config)
print()

# Transform the data
transformed_config = transform_to_uppercase(config)
print("Transformed config:")
print(transformed_config)
print()

# Convert back to YAML
yaml_output = dict_to_yaml(transformed_config)
print("YAML output:")
print(yaml_output)
print()

# Write to new file
with open('/workspace/config_upper.yaml', 'w') as f:
    f.write(yaml_output)

print("Transformation complete! File written to /workspace/config_upper.yaml")
