"""
Simple YAML parser and transformer without external dependencies.
Handles basic YAML structure for the config file.
"""

import re

def parse_yaml(content):
    """Parse simple YAML into Python dict"""
    lines = content.strip().split('\n')
    result = {}
    stack = [(result, -1)]  # (dict, indent_level)

    for line in lines:
        # Skip empty lines
        if not line.strip():
            continue

        # Calculate indentation
        indent = len(line) - len(line.lstrip())
        line = line.strip()

        # Skip comments
        if line.startswith('#'):
            continue

        # Parse key-value pair
        if ':' in line:
            key, value = line.split(':', 1)
            key = key.strip()
            value = value.strip()

            # Convert value types
            if value == 'null' or value == '':
                value = None
            elif value.lower() == 'true':
                value = True
            elif value.lower() == 'false':
                value = False
            elif value.isdigit():
                value = int(value)
            elif value.replace('.', '', 1).isdigit():
                value = float(value)

            # Pop stack until we find the right parent
            while stack and stack[-1][1] >= indent:
                stack.pop()

            parent_dict = stack[-1][0]

            # If value is None and no children, it might be a parent key
            if value is None or value == '':
                # Create a new dict for nested structure
                new_dict = {}
                parent_dict[key] = new_dict
                stack.append((new_dict, indent))
            else:
                parent_dict[key] = value

    return result

def dump_yaml(data, indent=0):
    """Convert Python dict to YAML string"""
    lines = []
    for key, value in data.items():
        if isinstance(value, dict):
            lines.append('  ' * indent + f'{key}:')
            lines.append(dump_yaml(value, indent + 1))
        elif value is None:
            lines.append('  ' * indent + f'{key}: null')
        elif isinstance(value, bool):
            lines.append('  ' * indent + f'{key}: {str(value).lower()}')
        else:
            lines.append('  ' * indent + f'{key}: {value}')
    return '\n'.join(lines)

def lowercase_keys(obj):
    """Recursively convert all keys to lowercase"""
    if isinstance(obj, dict):
        return {k.lower(): lowercase_keys(v) for k, v in obj.items()}
    elif isinstance(obj, list):
        return [lowercase_keys(item) for item in obj]
    else:
        return obj

def filter_null_values(obj):
    """Recursively filter out entries with null values"""
    if isinstance(obj, dict):
        filtered = {}
        for k, v in obj.items():
            if v is None:
                continue  # Skip null values
            elif isinstance(v, dict):
                nested_filtered = filter_null_values(v)
                if nested_filtered:  # Only include non-empty dicts
                    filtered[k] = nested_filtered
            elif isinstance(v, list):
                filtered[k] = filter_null_values(v)
            else:
                filtered[k] = v
        return filtered
    elif isinstance(obj, list):
        return [filter_null_values(item) for item in obj if item is not None]
    else:
        return obj

# Read the original YAML file
with open('/workspace/config.yaml', 'r') as f:
    content = f.read()

data = parse_yaml(content)

print("=" * 60)
print("ORIGINAL DATA:")
