def parse_simple_yaml(content):
    """Simple YAML parser for basic key-value structures."""
    result = {}
    current_section = None
    lines = content.strip().split('\n')

    for line in lines:
        # Skip empty lines
        if not line.strip():
            continue

        # Count leading spaces for indentation
        indent = len(line) - len(line.lstrip())
        stripped = line.strip()

        if indent == 0 and ':' in stripped:
            # Top-level key
            key = stripped.rstrip(':')
            current_section = key
            result[key] = {}
        elif indent > 0 and ':' in stripped:
            # Nested key-value
            parts = stripped.split(':', 1)
            key = parts[0].strip()
            value = parts[1].strip() if len(parts) > 1 and parts[1].strip() else None

            if current_section:
                result[current_section][key] = value

    return result

def transform_value(value):
    """Transform string values starting with 'ENV_' to environment variable values."""
    if isinstance(value, str) and value.startswith('ENV_'):
        env_var_name = value[4:]  # Remove 'ENV_' prefix
        # Get environment variable value, or keep original if not found
        return os.environ.get(env_var_name, value)
    elif isinstance(value, dict):
        return {k: transform_value(v) for k, v in value.items()}
    elif isinstance(value, list):
        return [transform_value(item) for item in value]
    else:
        return value

def dict_to_yaml(d, indent=0):
    """Convert dict to YAML format."""
    lines = []
    for key, value in d.items():
        if isinstance(value, dict):
            lines.append('  ' * indent + f'{key}:')
            lines.append(dict_to_yaml(value, indent + 1))
        else:
            if value is None:
                lines.append('  ' * indent + f'{key}:')
            else:
                lines.append('  ' * indent + f'{key}: {value}')
    return '\n'.join(lines)

