"""Extract all hyperlinks from an HTML file."""

from html.parser import HTMLParser


class LinkExtractor(HTMLParser):
    """Custom HTML parser to extract href attributes from anchor tags."""

    def __init__(self):
        super().__init__()
        self.links = []

    def handle_starttag(self, tag, attrs):
        """Extract href attribute from anchor tags."""
        if tag == 'a':
            for attr_name, attr_value in attrs:
                if attr_name == 'href':
                    # Skip empty or None href values
                    if attr_value and attr_value.strip():
                        self.links.append(attr_value)
                    break


def main():
    """Parse HTML file and extract links to output file."""
    # Read the HTML file
    with open('/workspace/page.html', 'r', encoding='utf-8') as f:
        html_content = f.read()

    # Parse and extract links
    parser = LinkExtractor()
    parser.feed(html_content)

    # Write links to output file
    with open('/workspace/links.txt', 'w', encoding='utf-8') as f:
        for link in parser.links:
            f.write(link + '\n')

    print(f"Extracted {len(parser.links)} link(s) to /workspace/links.txt")


if __name__ == '__main__':
    main()
