{"file_path":"/workspace/transform_yaml.py","content":"import asyncio
import micropip

async def main():
    await micropip.install('pyyaml')
    import yaml

    # Read the YAML file
    with open('/workspace/config.yaml', 'r') as f:
        data = yaml.safe_load(f)

    # Transform all string values to uppercase
    def uppercase_strings(obj):
        if isinstance(obj, dict):
            return {k: uppercase_strings(v) for k, v in obj.items()}
        elif isinstance(obj, list):
            return [uppercase_strings(item) for item in obj]
        elif isinstance(obj, str):
            return obj.upper()
        else:
            return obj

    transformed_data = uppercase_strings(data)

    # Write to new YAML file
    with open('/workspace/config_upper.yaml', 'w') as f:
        yaml.dump(transformed_data, f, default_flow_style=False, sort_keys=False)

    print("Transformation complete!")

asyncio.run(main())
"}

