{"command":"python3 << 'EOF'
import os
import hashlib
from collections import defaultdict

# Find all files > 1KB in /workspace
files_by_hash = defaultdict(list)

for root, dirs, files in os.walk('/workspace'):
    for file in files:
        filepath = os.path.join(root, file)
        try:
            # Check if file is larger than 1KB (1024 bytes)
            if os.path.getsize(filepath) > 1024:
                # Calculate MD5 hash
                md5_hash = hashlib.md5()
                with open(filepath, 'rb') as f:
                    for chunk in iter(lambda: f.read(4096), b''):
                        md5_hash.update(chunk)
                hash_value = md5_hash.hexdigest()
                files_by_hash[hash_value].append(filepath)
        except (OSError, IOError):
            pass

# Filter to only hashes with 2+ files, then sort and output
duplicates = {h: sorted(paths) for h, paths in files_by_hash.items() if len(paths) >= 2}

for hash_value in sorted(duplicates.keys()):
    for filepath in duplicates[hash_value]:
        print(f"{hash_value}  {filepath}")
EOF
