import json

def flatten_json(data, parent_key='', sep='.'):
    """Flatten nested JSON with dot-notation keys"""
    items = []

    if isinstance(data, dict):
        for k, v in data.items():
            new_key = f"{parent_key}{sep}{k}" if parent_key else k
            if isinstance(v, (dict, list)):
                items.extend(flatten_json(v, new_key, sep=sep).items())
            else:
                items.append((new_key, v))
    elif isinstance(data, list):
        for i, v in enumerate(data):
            new_key = f"{parent_key}{sep}{i}" if parent_key else str(i)
            if isinstance(v, (dict, list)):
                items.extend(flatten_json(v, new_key, sep=sep).items())
            else:
                items.append((new_key, v))
    else:
        return {parent_key: data}

    return dict(items)

# Read the nested JSON
with open('/workspace/nested.json', 'r') as f:
    nested_data = json.load(f)

# Flatten it
flattened = flatten_json(nested_data)

# Sort by keys and write to output file
with open('/workspace/flat.json', 'w') as f:
    json.dump(dict(sorted(flattened.items())), f, indent=2)

print("Flattened JSON:")
print(json.dumps(dict(sorted(flattened.items())), indent=2))
EOF"}

